    amount *= 1 + FIRST_INSURANCE_SURCHARGE;
  } else {
    amount *= 1 - SUBSEQUENT_DISCOUNT;
  }
  amount += PROCESSING_FEE;

  // Round up in MHPCO's favor
  return Math.ceil(amount - 1e-9);
}

